import { useEffect, useState, useCallback } from "react";
import "./CompanyDashboard.scss";

export default function CompanyDashboard() {
  const [role, setRole] = useState(null);
  const [bugs, setBugs] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [selectedBug, setSelectedBug] = useState(null);
  const [severity, setSeverity] = useState("low");
  const [reward, setReward] = useState("");

  const token = localStorage.getItem("token");

  const fetchCompanyBugs = useCallback(() => {
    if (!token) return;

    fetch("http://localhost:5000/api/bugs/company/bugs", {
      headers: { Authorization: `Bearer ${token}` },
    })
      .then(res => res.json())
      .then(data => {
        if (Array.isArray(data)) setBugs(data);
        else if (Array.isArray(data.bugs)) setBugs(data.bugs);
        else setBugs([]);
      });
  }, [token]);

  useEffect(() => {
    const storedRole = localStorage.getItem("role");

    if (!token) {
      window.location.href = "/";
      return;
    }

    if (storedRole !== "company" && storedRole !== "admin") {
      window.location.href = "/hacker";
      return;
    }

    setRole(storedRole);
    fetchCompanyBugs();
  }, [fetchCompanyBugs, token]);

  if (!role) return null;

  const openApprove = (bug) => {
    setSelectedBug(bug);
    setSeverity("low");
    setReward("");
    setShowModal(true);
  };

  const approveBug = async () => {
    if (!reward || Number(reward) <= 0) return;

    await fetch(
      `http://localhost:5000/api/bugs/validate/${selectedBug._id}`,
      {
        method: "PATCH",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({
          status: "approved",
          severity,
          reward: Number(reward),
        }),
      }
    );

    setShowModal(false);
    fetchCompanyBugs();
  };

  const rejectBug = async (id) => {
    await fetch(`http://localhost:5000/api/bugs/validate/${id}`, {
      method: "PATCH",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${token}`,
      },
      body: JSON.stringify({ status: "rejected" }),
    });

    fetchCompanyBugs();
  };

  return (
    <div className="company-dashboard">
      <header className="company-header">
        <h1>🏢 Company Dashboard</h1>
      </header>

      <div className="company-table">
        {bugs.length === 0 ? (
          <p className="muted">No bugs assigned.</p>
        ) : (
          <table>
            <thead>
              <tr>
                <th>Title</th>
                <th>Status</th>
                <th>Severity</th>
                <th>Reward</th>
                <th>Action</th>
              </tr>
            </thead>
            <tbody>
              {bugs.map(bug => (
                <tr key={bug._id}>
                  <td>{bug.title}</td>
                  <td className={`status ${bug.status}`}>{bug.status}</td>
                  <td className={`severity ${bug.severity}`}>{bug.severity}</td>
                  <td>₹{bug.reward || 0}</td>
                  <td>
                    {bug.status === "submitted" ? (
                      <>
                        <button className="approve" onClick={() => openApprove(bug)}>
                          Approve
                        </button>
                        <button className="reject" onClick={() => rejectBug(bug._id)}>
                          Reject
                        </button>
                      </>
                    ) : (
                      <span className="done">Done</span>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      {/* 🔥 HACKER THEME MODAL */}
      {showModal && (
        <div className="modal-backdrop">
          <div className="modal-box">
            <h2>Approve Bug</h2>

            <label>Severity</label>
            <select value={severity} onChange={e => setSeverity(e.target.value)}>
              <option value="low">Low</option>
              <option value="medium">Medium</option>
              <option value="high">High</option>
              <option value="critical">Critical</option>
            </select>

            <label>Reward</label>
            <input
              type="number"
              value={reward}
              onChange={e => setReward(e.target.value)}
              placeholder="Enter reward amount"
            />

            <div className="modal-actions">
              <button className="approve" onClick={approveBug}>Confirm</button>
              <button className="reject" onClick={() => setShowModal(false)}>Cancel</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
